// routes/export.js
const express = require('express');
const router = express.Router();
const csv = require('csv-parse');

// GET /api/export/csv?fields=name,email,role
// BUG: TypeError: fields.reduce is not a function
router.get('/csv', async (req, res) => {
  try {
    const fields = req.query.fields;
    // fields comes from query string as: "name,email,role"
    // Expected: ['name', 'email', 'role']

    const data = await loadCsvData();

    const filtered = fields.reduce((acc, field) => {
      if (data[0] && data[0][field]) {
        acc.push({ [field]: data[0][field] });
      }
      return acc;
    }, []);

    res.json({ data: filtered });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

function loadCsvData() {
  // Returns parsed CSV rows
  return [
    { name: 'Alice', email: 'alice@co.com', role: 'Engineer' },
    { name: 'Bob', email: 'bob@co.com', role: 'Designer' },
  ];
}

module.exports = router;

// routes/orders.js
const express = require('express');
const router = express.Router();
const db = require('../db');

// GET /api/orders/pending
// Returns all pending orders with their items and product details
// BUG: This endpoint is causing DB connection pool exhaustion
router.get('/pending', async (req, res) => {
  try {
    const orders = await db.query(`
      SELECT *
      FROM orders o
      JOIN order_items oi ON o.id = oi.order_id
      JOIN products p ON oi.product_id = p.id
      WHERE o.status = 'pending'
    `);

    res.json({ data: orders, count: orders.length });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

module.exports = router;

