// routes/checkout.js
const express = require('express');
const router = express.Router();
const db = require('../db');
const payment = require('../services/payment');

// POST /api/checkout/buy
// BUG: If user clicks twice quickly, both requests pass the check
// before either creates the order. Duplicate charges! 
router.post('/buy', async (req, res) => {
  const { userId, productId } = req.body;

  // Step 1: Check if pending order exists
  const existing = await db.query(
    'SELECT * FROM orders WHERE user_id = ? AND product_id = ? AND status = ?',
    [userId, productId, 'pending']
  );

  if (existing.length === 0) {
    // Step 2: Create order
    await db.query(
      'INSERT INTO orders (user_id, product_id, status) VALUES (?, ?, ?)',
      [userId, productId, 'pending']
    );

    // Step 3: Charge payment
    await payment.charge(userId, productId);

    // Step 4: Update status
    await db.query(
      'UPDATE orders SET status = ? WHERE user_id = ? AND product_id = ? AND status = ?',
      ['completed', userId, productId, 'pending']
    );

    res.json({ success: true });
  } else {
    res.json({ success: true, message: 'Order already exists' });
  }
});

module.exports = router;

